solutions.javascript:
// Solution
function walkDirectory(dirPath) {
  const fs = require('fs');
  fs.readdirSync(dirPath).forEach((file) => {
    const filePath = `${dirPath}/${file}`;
    const stats = fs.statSync(filePath);
    if (stats.isDirectory()) {
      walkDirectory(filePath);
    } else {
      console.log(file);
    }
  });
}
